    }

    if (t < k.toInt) {
      for ((x, y) <- teleportList(i)(j)) {
        val newT = t + 1
        if (cost < dist(x)(y)(newT)) {
          dist(x)(y)(newT) = cost
          pq.enqueue((cost, x, y, newT))
        }
      }
    }
  }

  Long.MaxValue
